import React from "react";

const WordpressTable = ({
	showCheckbox,
	showSortingIndicator,
	columns,
	rows,
	labels,
}) => {
	return (
		<table className="wp-list-table widefat fixed striped table-view-list comments">
			<thead>
				<tr>
					{showCheckbox && (
						<th
							id="cb"
							className="manage-column column-cb check-column"
						>
							<label
								className="screen-reader-text"
								htmlFor="cb-select-all-1"
							>
								Select All
							</label>
							<input id="cb-select-all-1" type="checkbox" />
						</th>
					)}
					{columns.map((col) => (
						<th
							key={col.id}
							scope="col"
							id={col.id}
							className={`manage-column column-${col.id} ${
								col.isSortable && "sortable desc"
							}`}
						>
							{col.isSortable ? (
								<a href="/">
									<span>{labels[col.id]}</span>
									{showSortingIndicator && (
										<span className="sorting-indicator"></span>
									)}
								</a>
							) : (
								labels[col.id]
							)}
						</th>
					))}
				</tr>
			</thead>
			<tbody>
				{rows.map((row, index) => (
					<tr
						key={row.id}
						className={`${index % 2 === 0 ? "alternate" : ""}`}
					>
						{showCheckbox && (
							<td className="manage-column column-cb check-column">
								<input
									type="checkbox"
									name={`cb[${row.id}]`}
									value={row.id}
								/>
							</td>
						)}
						{columns.map((col) => (
							<td
								key={`${row.id}_${col.id}`}
								className={`manage-column column-${col.id}`}
							>
								{row[col.id]}
							</td>
						))}
					</tr>
				))}
			</tbody>
			<tfoot>
				<tr>
					{showCheckbox && (
						<th className="manage-column column-cb check-column">
							<label
								className="screen-reader-text"
								htmlFor="cb-select-all-2"
							>
								Select All
							</label>
							<input id="cb-select-all-2" type="checkbox" />
						</th>
					)}
					{columns.map((col) => (
						<th
							key={col.id}
							scope="col"
							className={`manage-column column-${col.id} ${
								col.isSortable && "sortable desc"
							}`}
						>
							{col.isSortable ? (
								<a href="/">
									<span>{labels[col.id]}</span>
									{showSortingIndicator && (
										<span className="sorting-indicator"></span>
									)}
								</a>
							) : (
								labels[col.id]
							)}
						</th>
					))}
				</tr>
			</tfoot>
		</table>
	);
};

export default WordpressTable;
